using Microsoft.EntityFrameworkCore;

// Cosmos DB project context — demonstrates EF Core 9 breaking changes
// for the Cosmos DB provider.
class CosmosContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
        => options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "CatalogDb");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasPartitionKey(p => p.Category);

            // EF Core 9 breaking change: the default discriminator property
            // name changed from "Discriminator" to "$type".  Existing Cosmos
            // documents still carry "Discriminator", so we must pin the old
            // name to avoid a mismatch with stored data.
            b.HasDiscriminator<string>("Discriminator");
        });
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
    public string Category { get; set; } = default!;
}

using Microsoft.EntityFrameworkCore;

// EF Core 9 breaking change: the Cosmos DB provider no longer supports
// synchronous I/O.  All queries must use async equivalents (ToListAsync,
// FirstOrDefaultAsync, CountAsync, etc.).
class CosmosQueryService
{
    private readonly CosmosContext _db;

    public CosmosQueryService(CosmosContext db) => _db = db;

    // ❌ BEFORE (EF Core 8 — synchronous, now throws InvalidOperationException):
    //   var products = _db.Products.Where(p => p.Category == category).ToList();
    //   var count    = _db.Products.Count();
    //
    // ✅ AFTER (EF Core 9 — async only):
    public async Task<List<Product>> GetByCategoryAsync(string category)
        => await _db.Products
            .Where(p => p.Category == category)
            .ToListAsync();

    public async Task<int> CountAsync()
        => await _db.Products.CountAsync();
}

